    /**
    * Calls:
    * 1 - (500) GET:/v1/hospitais/maisProximo
    * 2 - (200) GET:/v1/hospitais/
    * 3 - (400) PUT:/v1/hospitais/{hospital_id}
    * 4 - (404) PUT:/v1/hospitais/{hospital_id}/pacientes/{patientId}
    * Found 3 potential faults. Type-codes: 100, 101
    */
    @Test(timeout = 60000)
    public void test_104_putOnPacientShowsFaults_100_101() throws Exception {
        
        // Fault100. HTTP Status 500. br/com/codenation/hospital/services/LocationService_109_findHospitalNearLocationBy
        // Fault101. Received A Response From API With A Structure/Data That Is Not Matching Its Schema. Type: validation.response.status.unknown Response status 500 not defined for path '/v1/hospitais/maisProximo'.
        given().accept("*/*")
                .header("x-EMextraHeader123", "")
                .get(baseUrlOfSut + "/v1/hospitais/maisProximo?" + 
                    "lat=4.19865377032155E8&" + 
                    "lon=4.424381180331451E8&" + 
                    "raioMaximo=-5.587740501284293E8&" + 
                    "EMextraParam123=42")
                .then()
                .statusCode(500)// br/com/codenation/hospital/services/LocationService_109_findHospitalNearLocationBy
                .assertThat()
                .contentType("application/json")
                .body("'status'", numberMatches(500))
                .body("'error'", containsString("Internal Server Error"))
                .body("'path'", containsString("/v1/hospitais/maisProximo"));
        
        given().accept("*/*")
                .header("x-EMextraHeader123", "")
                .get(baseUrlOfSut + "/v1/hospitais/?EMextraParam123=42")
                .then()
                .statusCode(200)
                .assertThat()
                .contentType("application/json")
                .body("size()", equalTo(0));
        
        // Fault101. Received A Response From API With A Structure/Data That Is Not Matching Its Schema. Type: validation.response.status.unknown Response status 400 not defined for path '/v1/hospitais/{hospital_id}'.
        given().accept("*/*")
                .header("x-EMextraHeader123", "_EM_554_XYZ_")
                .contentType("application/json")
                .body(" { " + 
                    " \"address\": \"Mge2Sxly9Cf\", " + 
                    " \"availableBeds\": 350, " + 
                    " \"longitude\": \"_EM_553_XYZ_\" " + 
                    " } ")
                .put(baseUrlOfSut + "/v1/hospitais/LvKlbfsJOY?EMextraParam123=42")
                .then()
                .statusCode(400)
                .assertThat()
                .body(isEmptyOrNullString());
        
        given().accept("*/*")
                .header("x-EMextraHeader123", "_EM_559_XYZ_")
                .contentType("application/json")
                .body(" { " + 
                    " \"active\": false, " + 
                    " \"cpf\": \"_EM_556_XYZ_\", " + 
                    " \"entryDate\": \"2051-06-10T23:43:32.241+09:29\", " + 
                    " \"gender\": \"unjm3rpQOFANff\", " + 
                    " \"id\": \"_EM_557_XYZ_\" " + 
                    " } ")
                .put(baseUrlOfSut + "/v1/hospitais/FW/pacientes/_EM_555_XYZ_")
                .then()
                .statusCode(404)
                .assertThat()
                .body(isEmptyOrNullString());
    }
    
    
